import React, { useState, useEffect, useRef } from 'react';
import { db } from '../../utils/firebase'; 
import { doc, getDoc, updateDoc, arrayUnion } from 'firebase/firestore';
import { Camera, RefreshCw, AlertTriangle, CheckCircle2, Lock, ShieldCheck, User } from 'lucide-react';

export default function MaterialWorker() {
  // Authentication & Session States
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState(null);

  // Logistics Inventory Strategy States
  const [operationType, setOperationType] = useState('WITHDRAW'); // WITHDRAW or DEPOSIT
  const [parentId, setParentId] = useState('platform no 1'); 
  const [quantity, setQuantity] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [errorAlert, setErrorAlert] = useState(null);
  const [successAlert, setSuccessAlert] = useState(null);
  
  // Media Capturing States
  const videoRef = useRef(null);
  const streamRef = useRef(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [previewUrl, setPreviewUrl] = useState(null);

  // Camera Management
  const startCamera = async () => {
    setErrorAlert(null);
    try {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: 640, height: 480 }
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          playPromise
            .then(() => setCameraActive(true))
            .catch((err) => {
              if (err.name !== 'AbortError') console.warn("Camera frame processing delayed.");
            });
        }
      }
    } catch (err) {
      setErrorAlert("Webcam / Camera peripheral component missing or denied.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current) videoRef.current.srcObject = null;
    setCameraActive(false);
  };

  useEffect(() => {
    if (isAuthenticated) {
      startCamera();
    }
    return () => stopCamera();
  }, [isAuthenticated]);

  const captureFrame = () => {
    if (!videoRef.current || !cameraActive) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth || 640;
    canvas.height = videoRef.current.videoHeight || 480;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
    
    try {
      const url = canvas.toDataURL('image/jpeg', 0.85);
      setPreviewUrl(url);
      stopCamera(); 
    } catch (err) {
      setErrorAlert("Image parsing conversion exception error.");
    }
  };

  // Internal Logic Handler for Credentials Verification
  const handleLoginSubmit = (e) => {
    e.preventDefault();
    setAuthError(null);

    // Hardcoded node administrator authentication matching system dashboard manager rules
    if (username.trim() === 'admin' && password === 'admin123') {
      setIsAuthenticated(true);
    } else {
      setAuthError("Invalid Administrator Credentials Key.");
    }
  };

  // Matrix State Commit Pipeline
  const handleProcessMatrixAudit = async (e) => {
    e.preventDefault();
    setIsProcessing(true);
    setErrorAlert(null);
    setSuccessAlert(null);

    if (!quantity || Number(quantity) <= 0) {
      setErrorAlert("Please provide valid material counts.");
      setIsProcessing(false);
      return;
    }

    try {
      const cleanRegistryKey = parentId.trim();
      const registryDocRef = doc(db, "registry", cleanRegistryKey);
      const registrySnap = await getDoc(registryDocRef);

      if (!registrySnap.exists()) {
        setErrorAlert(`Document "${cleanRegistryKey}" not found in Firestore "registry" collection.`);
        setIsProcessing(false);
        return;
      }

      await updateDoc(registryDocRef, {
        auditLogs: arrayUnion({
          strategyMode: operationType,
          quantity: Number(quantity),
          verificationPhoto: previewUrl || "https://via.placeholder.com/640",
          timestamp: new Date().toISOString(),
          status: "Verified",
          operatorSession: username
        })
      });

      setSuccessAlert(`Inventory ${operationType === 'WITHDRAW' ? 'Withdrawal' : 'Deposit'} committed successfully.`);
      setQuantity('');
      setPreviewUrl(null);
      startCamera();
    } catch (error) {
      setErrorAlert(`Database Write Error: ${error.message}`);
    } finally {
      setIsProcessing(false);
    }
  };

  // 1. LOGIN SCREEN INTERFACE
  if (!isAuthenticated) {
    return (
      <div style={{ backgroundColor: '#0A1128', minHeight: '100vh', display: 'flex', alignItems: 'center', justifycontent: 'center' }} className="w-full text-slate-100 p-6 flex flex-col items-center justify-center font-sans">
        <div style={{ backgroundColor: '#131C32', borderRadius: '16px', border: '1px solid #1E294B' }} className="w-full max-w-md shadow-2xl p-8">
          
          <div className="mb-6 text-center">
            <div className="w-12 h-12 bg-blue-600/20 text-blue-500 rounded-full flex items-center justify-center mx-auto mb-3 border border-blue-500/30">
              <Lock className="w-5 h-5" />
            </div>
            <h2 className="text-xl font-bold text-white tracking-wide">Node Access Control</h2>
            <p className="text-xs text-slate-400 mt-1">Provide administrator credentials to activate station</p>
          </div>

          {authError && (
            <div style={{ backgroundColor: 'rgba(127, 29, 29, 0.3)', border: '1px solid #991b1b' }} className="mb-4 p-3 text-red-200 rounded-lg flex items-center gap-2 text-xs">
              <AlertTriangle className="w-4 h-4 text-red-400 shrink-0" />
              <span>{authError}</span>
            </div>
          )}

          <form onSubmit={handleLoginSubmit} className="space-y-4">
            <div>
              <label className="block text-[11px] font-semibold uppercase tracking-wider text-slate-400 mb-1.5">Operator ID / Username</label>
              <div className="relative">
                <span className="absolute inset-y-0 left-0 flex items-center pl-3 text-slate-500"><User className="w-4 h-4" /></span>
                <input 
                  type="text" 
                  value={username} 
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="e.g. admin" 
                  style={{ backgroundColor: '#090F24', border: '1px solid #1E294B', color: '#F1F5F9' }}
                  className="w-full pl-10 pr-3 py-2 rounded-lg text-sm focus:outline-none focus:border-blue-500 transition-colors"
                  required
                />
              </div>
            </div>

            <div>
              <label className="block text-[11px] font-semibold uppercase tracking-wider text-slate-400 mb-1.5">Secure Pin / Password</label>
              <div className="relative">
                <span className="absolute inset-y-0 left-0 flex items-center pl-3 text-slate-500"><Lock className="w-4 h-4" /></span>
                <input 
                  type="password" 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••" 
                  style={{ backgroundColor: '#090F24', border: '1px solid #1E294B', color: '#F1F5F9' }}
                  className="w-full pl-10 pr-3 py-2 rounded-lg text-sm focus:outline-none focus:border-blue-500 transition-colors"
                  required
                />
              </div>
            </div>

            <button type="submit" className="w-full mt-2 py-2.5 bg-blue-600 hover:bg-blue-500 text-white text-xs font-semibold uppercase tracking-wider rounded-lg shadow-lg transition-all flex items-center justify-center gap-2">
              <ShieldCheck className="w-4 h-4" /> Verify Node Authorization
            </button>
          </form>

        </div>
      </div>
    );
  }

  // 2. MAIN STORAGE NODE APPLICATION PORTAL
  return (
    <div style={{ backgroundColor: '#0A1128', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }} className="w-full text-slate-100 p-6 font-sans">
      <div style={{ backgroundColor: '#131C32', borderRadius: '16px', border: '1px solid #1E294B' }} className="w-full max-w-md shadow-2xl p-6">
        
        {/* Header Block UI Elements */}
        <div className="mb-6 text-center">
          <h2 className="text-xl font-extrabold text-white tracking-wide">Material Storage Node Portal</h2>
          <p className="text-xs text-slate-400 mt-1">Active Profile Session: <span className="text-blue-400 font-medium">{username}</span></p>
        </div>

        {/* Dynamic Context Toast Banners */}
        {errorAlert && (
          <div style={{ backgroundColor: 'rgba(127, 29, 29, 0.3)', border: '1px solid #991b1b' }} className="mb-4 p-3 text-red-200 rounded-lg flex items-start gap-2 text-xs">
            <AlertTriangle className="w-4 h-4 text-red-400 shrink-0 mt-0.5" />
            <span>{errorAlert}</span>
          </div>
        )}

        {successAlert && (
          <div style={{ backgroundColor: 'rgba(6, 78, 59, 0.3)', border: '1px solid #065f46' }} className="mb-4 p-3 text-emerald-200 rounded-lg flex items-start gap-2 text-xs">
            <CheckCircle2 className="w-4 h-4 text-emerald-400 shrink-0 mt-0.5" />
            <span>{successAlert}</span>
          </div>
        )}

        <form onSubmit={handleProcessMatrixAudit} className="space-y-5">
          
          {/* Strategy Operation Choice Pills */}
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1.5">Logistics Inventory Operations Strategy</label>
            <div className="grid grid-cols-2 gap-3">
              <button 
                type="button" 
                onClick={() => setOperationType('WITHDRAW')}
                className={`py-2.5 px-3 rounded-lg text-xs font-bold uppercase tracking-wider transition-all border flex items-center justify-center gap-1.5 ${operationType === 'WITHDRAW' ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-600/20' : 'bg-[#090F24] border-[#1E294B] text-slate-400 hover:text-slate-200'}`}
              >
                <div className={`w-2 h-2 rounded-full ${operationType === 'WITHDRAW' ? 'bg-white' : 'bg-red-500'}`} />
                Withdraw (Stock Out)
              </button>
              <button 
                type="button" 
                onClick={() => setOperationType('DEPOSIT')}
                className={`py-2.5 px-3 rounded-lg text-xs font-bold uppercase tracking-wider transition-all border flex items-center justify-center gap-1.5 ${operationType === 'DEPOSIT' ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-600/20' : 'bg-[#090F24] border-[#1E294B] text-slate-400 hover:text-slate-200'}`}
              >
                <div className={`w-2 h-2 rounded-full ${operationType === 'DEPOSIT' ? 'bg-white' : 'bg-blue-500'}`} />
                Deposit (Stock In)
              </button>
            </div>
          </div>

          {/* Hardcoded Key Reference */}
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1.5">Active Station Key</label>
            <input 
              type="text"
              value={parentId}
              onChange={(e) => setParentId(e.target.value)}
              style={{ backgroundColor: '#090F24', border: '1px solid #1E294B', color: '#94A3B8' }}
              className="w-full px-3 py-2 rounded-lg text-xs focus:outline-none"
              placeholder="Registry Path"
            />
          </div>

          {/* Quantity Counts Segment Input */}
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1.5">Material Quantity / Unit Shift Weight</label>
            <input 
              type="number"
              min="1"
              value={quantity}
              onChange={(e) => setQuantity(e.target.value)}
              style={{ backgroundColor: '#090F24', border: '1px solid #1E294B', color: '#F1F5F9' }}
              className="w-full px-3 py-2 rounded-lg text-sm focus:outline-none focus:border-blue-500 transition-colors"
              placeholder="Provide material counts..."
            />
          </div>

          {/* Verification Photo Streams Block */}
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1.5">State Audit Photo Block Verification</label>
            
            <div style={{ backgroundColor: '#090F24', border: '1px solid #1E294B' }} className="relative w-full aspect-video rounded-xl overflow-hidden flex items-center justify-center border-dashed">
              {previewUrl ? (
                <img src={previewUrl} alt="Audit verification snapshot" className="w-full h-full object-cover" />
              ) : (
                <video ref={videoRef} className={`w-full h-full object-cover ${!cameraActive ? 'hidden' : 'block'}`} playsInline muted />
              )}

              {!cameraActive && !previewUrl && (
                <div className="text-center p-4">
                  <Camera className="w-8 h-8 text-slate-600 mx-auto mb-2 animate-pulse" />
                  <p className="text-xs text-slate-500">Camera initialization loop stream...</p>
                </div>
              )}
            </div>

            <div className="mt-2.5">
              {previewUrl ? (
                <button type="button" onClick={() => { setPreviewUrl(null); startCamera(); }} style={{ backgroundColor: '#1E294B', border: '1px solid #334155' }} className="w-full py-2 px-3 hover:bg-slate-700 text-slate-200 text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-colors">
                  <RefreshCw className="w-3.5 h-3.5" /> Initialize Material Device Lens Capture
                </button>
              ) : (
                <button type="button" onClick={captureFrame} disabled={!cameraActive} className="w-full py-2 px-3 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-800 disabled:text-slate-600 text-white text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-colors">
                  <Camera className="w-3.5 h-3.5" /> Capture Verification Frame
                </button>
              )}
            </div>
          </div>

          {/* Core Master Submit Action Button */}
          <button
            type="submit"
            disabled={isProcessing}
            className={`w-full mt-4 py-3 px-4 text-white text-xs font-bold uppercase tracking-widest rounded-lg transition-all shadow-xl flex items-center justify-center gap-2 ${operationType === 'WITHDRAW' ? 'bg-gradient-to-r from-red-600 to-rose-600 hover:from-red-500 hover:to-rose-500' : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500'}`}
          >
            {isProcessing ? (
              "Synchronizing State Matrix..."
            ) : (
              `Confirm & Commit ${operationType}`
            )}
          </button>
        </form>
      </div>
    </div>
  );
}
